class _UniffiConverterBool:
    @classmethod
    def check_lower(cls, value):
        return not not value

    @classmethod
    def lower(cls, value):
        return 1 if value else 0

    @staticmethod
    def lift(value):
        return value != 0

    @classmethod
    def read(cls, buf):
        return cls.lift(buf.read_u8())

    @classmethod
    def write(cls, value, buf):
        buf.write_u8(value)

class _UniffiConverterString:
    @staticmethod
    def check_lower(value):
        if not isinstance(value, str):
            raise TypeError("argument must be str, not {}".format(type(value).__name__))
        return value

    @staticmethod
    def read(buf):
        size = buf.read_i32()
        if size < 0:
            raise InternalError("Unexpected negative string length")
        utf8_bytes = buf.read(size)
        return utf8_bytes.decode("utf-8")

    @staticmethod
    def write(value, buf):
        utf8_bytes = value.encode("utf-8")
        buf.write_i32(len(utf8_bytes))
        buf.write(utf8_bytes)

    @staticmethod
    def lift(buf):
        with buf.consume_with_stream() as stream:
            return stream.read(stream.remaining()).decode("utf-8")

    @staticmethod
    def lower(value):
        with _UniffiRustBuffer.alloc_with_builder() as builder:
            builder.write(value.encode("utf-8"))
            return builder.finalize()

class _UniffiConverterBytes(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        size = buf.read_i32()
        if size < 0:
            raise InternalError("Unexpected negative byte string length")
        return buf.read(size)

    @staticmethod
    def check_lower(value):
        try:
            memoryview(value)
        except TypeError:
            raise TypeError("a bytes-like object is required, not {!r}".format(type(value).__name__))

    @staticmethod
    def write(value, buf):
        buf.write_i32(len(value))
        buf.write(value)








class BrowserConfig:
    """
    Configuration for the Browser instance.
    """

    headless: "bool"
    """
    Whether to run the browser in headless mode.
    """

    stealth: "bool"
    """
    Whether to apply stealth patches to the binary.
    """

    detached: "bool"
    """
    Whether to run the browser as a detached process.
    """

    executable_path: "typing.Optional[str]"
    """
    Optional path to the browser executable.
    """

    def __init__(self, *, headless: "bool", stealth: "bool", detached: "bool", executable_path: "typing.Optional[str]"):
        self.headless = headless
        self.stealth = stealth
        self.detached = detached
        self.executable_path = executable_path

    def __str__(self):
        return "BrowserConfig(headless={}, stealth={}, detached={}, executable_path={})".format(self.headless, self.stealth, self.detached, self.executable_path)

    def __eq__(self, other):
        if self.headless != other.headless:
            return False
        if self.stealth != other.stealth:
            return False
        if self.detached != other.detached:
            return False
        if self.executable_path != other.executable_path:
            return False
        return True

class _UniffiConverterTypeBrowserConfig(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        return BrowserConfig(
            headless=_UniffiConverterBool.read(buf),
            stealth=_UniffiConverterBool.read(buf),
            detached=_UniffiConverterBool.read(buf),
            executable_path=_UniffiConverterOptionalString.read(buf),
        )

    @staticmethod
    def check_lower(value):
        _UniffiConverterBool.check_lower(value.headless)
        _UniffiConverterBool.check_lower(value.stealth)
        _UniffiConverterBool.check_lower(value.detached)
        _UniffiConverterOptionalString.check_lower(value.executable_path)

    @staticmethod
    def write(value, buf):
        _UniffiConverterBool.write(value.headless, buf)
        _UniffiConverterBool.write(value.stealth, buf)
        _UniffiConverterBool.write(value.detached, buf)
        _UniffiConverterOptionalString.write(value.executable_path, buf)


# XcelerateError
# We want to define each variant as a nested class that's also a subclass,
# which is tricky in Python.  To accomplish this we're going to create each
# class separately, then manually add the child classes to the base class's
# __dict__.  All of this happens in dummy class to avoid polluting the module
# namespace.
class XcelerateError(Exception):
    pass

_UniffiTempXcelerateError = XcelerateError

class XcelerateError:  # type: ignore
    class WsError(_UniffiTempXcelerateError):

        def __repr__(self):
            return "XcelerateError.WsError({})".format(repr(str(self)))
    _UniffiTempXcelerateError.WsError = WsError # type: ignore
    class SerdeError(_UniffiTempXcelerateError):

        def __repr__(self):
            return "XcelerateError.SerdeError({})".format(repr(str(self)))
    _UniffiTempXcelerateError.SerdeError = SerdeError # type: ignore
    class CdpResponseError(_UniffiTempXcelerateError):

        def __repr__(self):
            return "XcelerateError.CdpResponseError({})".format(repr(str(self)))
    _UniffiTempXcelerateError.CdpResponseError = CdpResponseError # type: ignore
    class HttpError(_UniffiTempXcelerateError):

        def __repr__(self):
            return "XcelerateError.HttpError({})".format(repr(str(self)))
    _UniffiTempXcelerateError.HttpError = HttpError # type: ignore
    class NotFound(_UniffiTempXcelerateError):

        def __repr__(self):
            return "XcelerateError.NotFound({})".format(repr(str(self)))
    _UniffiTempXcelerateError.NotFound = NotFound # type: ignore
    class InternalError(_UniffiTempXcelerateError):

        def __repr__(self):
            return "XcelerateError.InternalError({})".format(repr(str(self)))
    _UniffiTempXcelerateError.InternalError = InternalError # type: ignore

XcelerateError = _UniffiTempXcelerateError # type: ignore
del _UniffiTempXcelerateError


class _UniffiConverterTypeXcelerateError(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return XcelerateError.WsError(
                _UniffiConverterString.read(buf),
            )
        if variant == 2:
            return XcelerateError.SerdeError(
                _UniffiConverterString.read(buf),
            )
        if variant == 3:
            return XcelerateError.CdpResponseError(
                _UniffiConverterString.read(buf),
            )
        if variant == 4:
            return XcelerateError.HttpError(
                _UniffiConverterString.read(buf),
            )
        if variant == 5:
            return XcelerateError.NotFound(
                _UniffiConverterString.read(buf),
            )
        if variant == 6:
            return XcelerateError.InternalError(
                _UniffiConverterString.read(buf),
            )
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if isinstance(value, XcelerateError.WsError):
            return
        if isinstance(value, XcelerateError.SerdeError):
            return
        if isinstance(value, XcelerateError.CdpResponseError):
            return
        if isinstance(value, XcelerateError.HttpError):
            return
        if isinstance(value, XcelerateError.NotFound):
            return
        if isinstance(value, XcelerateError.InternalError):
            return

    @staticmethod
    def write(value, buf):
        if isinstance(value, XcelerateError.WsError):
            buf.write_i32(1)
        if isinstance(value, XcelerateError.SerdeError):
            buf.write_i32(2)
        if isinstance(value, XcelerateError.CdpResponseError):
            buf.write_i32(3)
        if isinstance(value, XcelerateError.HttpError):
            buf.write_i32(4)
        if isinstance(value, XcelerateError.NotFound):
            buf.write_i32(5)
        if isinstance(value, XcelerateError.InternalError):
            buf.write_i32(6)



class _UniffiConverterOptionalString(_UniffiConverterRustBuffer):
    @classmethod
    def check_lower(cls, value):
        if value is not None:
            _UniffiConverterString.check_lower(value)

    @classmethod
    def write(cls, value, buf):
        if value is None:
            buf.write_u8(0)
            return

        buf.write_u8(1)
        _UniffiConverterString.write(value, buf)

    @classmethod
    def read(cls, buf):
        flag = buf.read_u8()
        if flag == 0:
            return None
        elif flag == 1:
            return _UniffiConverterString.read(buf)
        else:
            raise InternalError("Unexpected flag byte for optional type")

